  1	import React, { Dispatch, SetStateAction, useMemo } from 'react';
  2	
  3	import { modelToGroupVersionKind, NodeModel } from '@kubevirt-ui/kubevirt-api/console';
  4	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes';
  5	import InlineFilterSelect from '@kubevirt-utils/components/FilterSelect/InlineFilterSelect';
  6	import { EnhancedSelectOptionProps } from '@kubevirt-utils/components/FilterSelect/utils/types';
  7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  8	import { getName } from '@kubevirt-utils/resources/shared';
  9	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  Button,
 12	  ButtonVariant,
 13	  Checkbox,
 14	  Flex,
 15	  FormGroup,
 16	  Popover,
 17	  PopoverPosition,
 18	  Stack,
 19	  StackItem,
 20	} from '@patternfly/react-core';
 21	import { HelpIcon } from '@patternfly/react-icons';
 22	
 23	type CheckupsNetworkFormNodes = {
 24	  isNodesChecked: boolean;
 25	  nodeSource: string;
 26	  nodeTarget: string;
 27	  setIsNodesChecked: Dispatch<SetStateAction<boolean>>;
 28	  setNodeSource: Dispatch<SetStateAction<string>>;
 29	  setNodeTarget: Dispatch<SetStateAction<string>>;
 30	};
 31	
 32	const CheckupsNetworkFormNodes = ({
 33	  isNodesChecked,
 34	  nodeSource,
 35	  nodeTarget,
 36	  setIsNodesChecked,
 37	  setNodeSource,
 38	  setNodeTarget,
 39	}) => {
 40	  const { t } = useKubevirtTranslation();
 41	
 42	  const [nodes] = useK8sWatchResource<IoK8sApiCoreV1Node[]>({
 43	    groupVersionKind: modelToGroupVersionKind(NodeModel),
 44	    isList: true,
 45	  });
 46	
 47	  const options: EnhancedSelectOptionProps[] = useMemo(
 48	    () =>
 49	      nodes?.map((node) => {
 50	        const name = getName(node);
 51	        return { children: name, value: name };
 52	      }),
 53	    [nodes],
 54	  );
 55	
 56	  return (
 57	    <>
 58	      <Flex>
 59	        <Checkbox
 60	          id="nodes"
 61	          isChecked={isNodesChecked}
 62	          label={t('Select nodes')}
 63	          name="nodes"
 64	          onChange={(_event, checked) => setIsNodesChecked(checked)}
 65	        />
 66	        <Popover
 67	          bodyContent={t('If no nodes are specified, random nodes are selected.')}
 68	          position={PopoverPosition.right}
 69	        >
 70	          <Button style={{ paddingLeft: 0 }} variant={ButtonVariant.plain}>
 71	            <HelpIcon />
 72	          </Button>
 73	        </Popover>
 74	      </Flex>
 75	      {isNodesChecked && (
 76	        <Stack hasGutter>
 77	          <StackItem>
 78	            <FormGroup fieldId="source-nodes" isRequired label={t('Source node')}>
 79	              <InlineFilterSelect
 80	                options={options}
 81	                selected={nodeSource}
 82	                setSelected={setNodeSource}
 83	                toggleProps={{ placeholder: t('Select source node') }}
 84	              />
 85	            </FormGroup>
 86	          </StackItem>
 87	          <StackItem>
 88	            <FormGroup fieldId="target-nodes" isRequired label={t('Target node')}>
 89	              <InlineFilterSelect
 90	                options={options}
 91	                selected={nodeTarget}
 92	                setSelected={setNodeTarget}
 93	                toggleProps={{ placeholder: t('Select target node') }}
 94	              />
 95	            </FormGroup>
 96	          </StackItem>
 97	        </Stack>
 98	      )}
 99	    </>
100	  );
101	};
102	
103	export default CheckupsNetworkFormNodes;

